fn main() {
    let number = 7;
    if number % 2 == 0 {
        println!("偶数");
    } else {
        println!("奇数");
    }

    // loop 可以返回值
    let mut count = 0;
    let result = loop {
        count += 1;
        if count >= 3 {
            break count * 2;
        }
    };
    println!("loop 结果: {}", result);

    // while 循环
    let mut n = 3;
    while n > 0 {
        println!("while: {}", n);
        n -= 1;
    }

    // for 循环遍历范围
    for i in 1..4 {
        println!("for: {}", i);
    }

    // for 循环遍历集合并获取索引
    let arr = [10, 20, 30];
    for (idx, val) in arr.iter().enumerate() {
        println!("arr[{}] = {}", idx, val);
    }

    // if let 简化模式匹配
    let some_value = Some(5);
    if let Some(v) = some_value {
        println!("if let 匹配到: {}", v);
    }
}

fn main() {
    // 不可变借用
    let s1 = String::from("hello");
    let len = calculate_length(&s1);
    println!("'{}' 的长度是 {}。", s1, len);

    // 可变借用
    let mut s2 = String::from("hello");
    change(&mut s2);
    println!("修改后: {}", s2);

    // 所有权转移与 clone
    let s3 = s1.clone();
    println!("s1 = {}, s3 = {}", s1, s3);

    // 切片不拥有数据
    let text = String::from("hello world");
    let first = &text[..5];
    let second = &text[6..];
    println!("{} | {}", first, second);
}

fn calculate_length(s: &String) -> usize {
    s.len()
}

fn change(s: &mut String) {
    s.push_str(", world");
}

#[derive(Debug, Clone, PartialEq)]
struct Rectangle {
    width: u32,
    height: u32,
}

impl Rectangle {
    // 关联函数，常用于构造
    fn square(size: u32) -> Self {
        Self { width: size, height: size }
    }

    // 方法
    fn area(&self) -> u32 {
        self.width * self.height
    }

    fn can_hold(&self, other: &Rectangle) -> bool {
        self.width > other.width && self.height > other.height
    }

    // 可变方法示例
    fn scale(&mut self, factor: u32) {
        self.width *= factor;
        self.height *= factor;
    }
}

fn main() {
    let mut rect1 = Rectangle { width: 30, height: 50 };
    println!("矩形: {:?}", rect1);
    println!("矩形面积: {}", rect1.area());

    rect1.scale(2);
    println!("放大后: {:?}, 面积: {}", rect1, rect1.area());

    let rect2 = Rectangle { width: 10, height: 40 };
    println!("rect1 能容纳 rect2? {}", rect1.can_hold(&rect2));

    let sq = Rectangle::square(20);
    println!("正方形: {:?}, 面积: {}", sq, sq.area());
}

enum Message {
    Quit,
    Move { x: i32, y: i32 },
    Write(String),
}

fn main() {
    let msg = Message::Move { x: 10, y: 20 };

    match msg {
        Message::Quit => println!("退出"),
        Message::Move { x, y } => println!("移动到 ({}, {})", x, y),
        Message::Write(text) => println!("写入: {}", text),
    }

    // Option 的基本使用
    let some_number = Some(5);
    if let Some(n) = some_number {
        println!("值是: {}", n);
    }

    let absent: Option<i32> = None;
    println!("absent: {:?}", absent);

    // 处理 Option 的常用模式
    let val = Some(7);
    match val {
        Some(n) if n > 5 => println!("大于 5: {}", n),
        Some(_) => println!("不大于 5"),
        None => println!("没有值"),
    }

    // unwrap_or 提供默认值
