struct FileGuard {
    name: String,
}

impl FileGuard {
    fn new(name: &str) -> FileGuard {
        println!("打开文件: {}", name);
        FileGuard {
            name: name.to_string(),
        }
    }
}

impl Drop for FileGuard {
    fn drop(&mut self) {
        println!("关闭文件: {}", self.name);
    }
}

fn main() {
    {
        let file = FileGuard::new("data.txt");
        println!("使用文件: {}", file.name);
    } // file 离开作用域，drop 被调用

    println!("文件已自动关闭");

    // 也可以显式 drop
    let file2 = FileGuard::new("temp.txt");
    drop(file2);
    println!("temp.txt 已提前关闭");
}

