// Rust 用结构体 + impl 实现封装
struct BankAccount {
    owner: String,
    balance: f64,
}

impl BankAccount {
    fn new(owner: &str, balance: f64) -> Self {
        BankAccount {
            owner: owner.to_string(),
            balance,
        }
    }

    fn deposit(&mut self, amount: f64) {
        if amount > 0.0 {
            self.balance += amount;
        }
    }

    fn balance(&self) -> f64 {
        self.balance
    }
}

// Rust 用 trait 实现多态
trait Animal {
