        self.engine.start();
    }
}

// 方案二：Trait 默认实现
trait Greetable {
    fn name(&self) -> &str;

    fn greet(&self) {
        println!("你好，我是 {}", self.name());
    }
}

struct Person {
    name: String,
}

impl Greetable for Person {
    fn name(&self) -> &str {
        &self.name
    }
}

